VALUES ('Medical Gel Ultrasound Gel (Variant #1)', 'Medical Gel Ultrasound Gel (Variant #1)', 'specialty', 'medical', 'gel', NULL, '[{"name_en": "Carbomer (Carbopol)", "name_ar": null, "cas_number": "9007-20-9", "percentage": 0.8, "function": "Thickener / rheology", "phase": "Part A"}, {"name_en": "Sodium Hydroxide (20% Solution)", "name_ar": null, "cas_number": "1310-73-2", "percentage": 0.8, "function": "Strong alkali", "phase": "Part A"}, {"name_en": "Sodium Carboxymethyl Cellulose (CMC)", "name_ar": null, "cas_number": "9004-32-4", "percentage": 0.2, "function": "Thickener", "phase": "Part A"}, {"name_en": "Monopropylene Glycol (MPG)", "name_ar": null, "cas_number": "57-55-6", "percentage": 10.0, "function": "Solvent / humectant", "phase": "Part A"}, {"name_en": "Methyl Paraben", "name_ar": null, "cas_number": "99-76-3", "percentage": 0.2, "function": "Preservative", "phase": "Part A"}, {"name_en": "Deionized Water", "name_ar": null, "cas_number": "7732-18-5", "percentage": 88.0, "function": "Vehicle", "phase": "Part A"}]'::jsonb, '{"order_of_addition": "Charge 10 lt water in the process tank. Add carbomer and carboxymethylcellulose. Disperse two ingredients in the water thoroughly. Wait a day for wetting carbomer and carboxymethyl cellulose in the water completely. After day, Start to mix again. Add remain of water in the process tank and mix well. Add monopropylene glycol and methyl paraben while constant mixing. Finally, add sodium hydroxide and mix until PH: 7 and a clear, viscous solution is obtained. Homogenous and clear is reached. Process is completed.", "temperature_c": null, "ph_target": null, "mixing_speed_rpm": null, "mixing_time_min": null}'::jsonb, '{"appearance": null, "viscosity_cp": null, "density_g_ml": null, "shelf_life_months": null}'::jsonb, '[]'::jsonb, 'private_library', 'Jamil Abduljaleel — Personal Formula Library v2', 'Jamil Abduljaleel', 2026, 'FA-2026-X02344', 88, 'en', TRUE)
